+/**
+ * Custom error class for factorial calculation errors
+ */
+class FactorialError extends Error {
+  constructor(message, value) {
+    super(message);
+    this.name = 'FactorialError';
+    this.value = value;
+  }
+}
+
+/**
+ * Calculates the factorial of a non-negative integer using recursion
+ * 
+ * @param {number} n - The non-negative integer to calculate factorial for
+ * @returns {number} The factorial of n (n!)
+ * @throws {FactorialError} If n is negative, not an integer, or not a number
+ * 
+ * @example
+ * const result = factorial(5);  // Returns 120
+ * 
+ * @example
+ * const result = factorial(0);  // Returns 1 (base case)
+ * 
+ * @complexity
+ * Time: O(n) - Makes n recursive calls
+ * Space: O(n) - Call stack depth of n
+ */
+const factorial = (n) => {
+  // Input validation
+  if (typeof n !== 'number') {
+    throw new FactorialError(
+      `Expected a number, but received ${typeof n}`,
+      n
+    );
+  }
+
+  if (!Number.isFinite(n)) {
+    throw new FactorialError(
+      'Cannot calculate factorial of Infinity or NaN',
+      n
+    );
+  }
+
+  if (!Number.isInteger(n)) {
+    throw new FactorialError(
+      `Factorial is only defined for integers, received ${n}`,
+      n
+    );
+  }
+
+  if (n < 0) {
+    throw new FactorialError(
+      `Factorial is not defined for negative numbers, received ${n}`,
+      n
+    );
+  }
+
+  // Handle large numbers that would cause overflow
+  if (n > 170) {
+    throw new FactorialError(
+      `Factorial of ${n} would exceed JavaScript's maximum number value (170! is the largest safe factorial)`,
+      n
+    );
+  }
+
+  // Base case
+  if (n === 0 || n === 1) {
+    return 1;
+  }
+
+  // Recursive case
+  return n * factorial(n - 1);
+};
+
+/**
